  1→/**
  2→ * DealRepository tests
  3→ *
  4→ * Uses tsx for test execution. Creates test fixtures in dev.db.
  5→ * Tests all CRUD operations, stage transitions, history tracking, and soft-delete.
  6→ */
  7→
  8→import { describe, it, before, after } from 'node:test';
  9→import assert from 'node:assert';
 10→import { deals } from './deals.js';
 11→import { prisma } from './prisma.js';
 12→
 13→const TEST = 't01-';
 14→
 15→describe('DealRepository', { concurrency: false }, () => {
 16→  let pipelineId: string;
 17→  let newStageId: string;
 18→  let qualifiedStageId: string;
 19→  let wonStageId: string;
 20→  let lostStageId: string;
 21→  let userId: string;
 22→  let managerId: string;
 23→  let contactId: string;
 24→
 25→  before(async () => {
 26→    // Clean up leftover test data from previous runs.
 27→    // Deals have auto-generated UUIDs so we filter by test pipelineId.
 28→    // DealHistory cascades on Deal delete (onDelete: Cascade in schema).
 29→    await prisma.deal.deleteMany({ where: { pipelineId: { startsWith: TEST } } });
 30→    await prisma.dealStage.deleteMany({ where: { id: { startsWith: TEST } } });
 31→    await prisma.pipeline.deleteMany({ where: { id: { startsWith: TEST } } });
 32→    await prisma.user.deleteMany({ where: { id: { startsWith: TEST } } });
 33→    await prisma.contact.deleteMany({ where: { id: { startsWith: TEST } } });
 34→
 35→    // Create test pipeline
 36→    pipelineId = `${TEST}pipeline`;
 37→    await prisma.pipeline.create({
 38→      data: {
 39→        id: pipelineId,
 40→        code: `${TEST}default`,
 41→        name: 'Test Pipeline',
 42→        createdAt: new Date(),
 43→      },
 44→    });
 45→
 46→    // Create test stages
 47→    newStageId = `${TEST}new`;
 48→    qualifiedStageId = `${TEST}qualified`;
 49→    wonStageId = `${TEST}won`;
 50→    lostStageId = `${TEST}lost`;
 51→
 52→    const stages = [
 53→      { id: newStageId, code: `${TEST}new`, name: 'New', order: 1, probability: 10 },
 54→      { id: qualifiedStageId, code: `${TEST}qualified`, name: 'Qualified', order: 2, probability: 30 },
 55→      { id: wonStageId, code: `${TEST}won`, name: 'Won', order: 7, probability: 100, isWonStage: true },
 56→      { id: lostStageId, code: `${TEST}lost`, name: 'Lost', order: 8, probability: 0, isLostStage: true },
 57→    ];
 58→
 59→    for (const s of stages) {
 60→      await prisma.dealStage.create({
 61→        data: { ...s, pipelineId, color: '#888888' },
 62→      });
 63→    }
 64→
 65→    // Create test users (schema requires manual id, updatedAt)
 66→    userId = `${TEST}user-a`;
 67→    managerId = `${TEST}user-b`;
 68→    const now = new Date();
 69→    await prisma.user.create({
 70→      data: { id: userId, email: `${TEST}a@test.com`, name: 'Test User A', passwordHash: 'hash-a', updatedAt: now },
 71→    });
 72→    await prisma.user.create({
 73→      data: { id: managerId, email: `${TEST}b@test.com`, name: 'Test User B', passwordHash: 'hash-b', updatedAt: now },
 74→    });
 75→
 76→    // Create test contact (schema requires manual id, updatedAt)
 77→    contactId = `${TEST}contact`;
 78→    await prisma.contact.create({
 79→      data: { id: contactId, type: 'company', companyName: 'Test Corp', updatedAt: now },
 80→    });
 81→  });
 82→
 83→  after(async () => {
 84→    // Deals have auto-generated UUIDs; filter by test pipelineId.
 85→    // DealHistory cascades on Deal delete (onDelete: Cascade in schema).
 86→    await prisma.deal.deleteMany({ where: { pipelineId: { startsWith: TEST } } });
 87→    await prisma.dealStage.deleteMany({ where: { id: { startsWith: TEST } } });
 88→    await prisma.pipeline.deleteMany({ where: { id: { startsWith: TEST } } });
 89→    await prisma.user.deleteMany({ where: { id: { startsWith: TEST } } });
 90→    await prisma.contact.deleteMany({ where: { id: { startsWith: TEST } } });
 91→    await prisma.$disconnect();
 92→  });
 93→
 94→  let createdDealId: string;
 95→  let createdDealNumber: string;
 96→
 97→  // ── Create ──────────────────────────────────────────────────────────
 98→
 99→  it('should create a deal with auto-generated UUID and С-YYYY-NNNNN number', async () => {
100→    const deal = await deals.create({
101→      title: 'Test Deal Auto',
102→      pipelineId,
103→      stageId: newStageId,
104→    });
105→
106→    assert.ok(deal, 'Deal should be created');
107→    assert.ok(deal.id, 'Deal should have an ID');
108→    assert.ok(deal.number, 'Deal should have auto-generated number');
109→    assert.match(deal.number, /^С-\d{4}-\d{5}$/, 'Number format: С-YYYY-NNNNN');
110→    assert.strictEqual(deal.title, 'Test Deal Auto');
111→    assert.strictEqual(deal.amount, 0, 'Default amount should be 0');
112→    assert.strictEqual(deal.currency, 'RUB', 'Default currency should be RUB');
113→    assert.strictEqual(deal.deletedAt, null, 'New deal should not be deleted');
114→    createdDealId = deal.id;
115→    createdDealNumber = deal.number;
116→  });
117→
118→  it('should create a deal with provided values overriding defaults', async () => {
119→    const deal = await deals.create({
120→      title: 'Test Deal Custom',
121→      pipelineId,
122→      stageId: newStageId,
123→      amount: 150_000,
124→      currency: 'USD',
125→      contactId,
126→      managerId,
127→      description: 'Custom description',
128→    });
129→
130→    assert.strictEqual(deal.title, 'Test Deal Custom');
131→    assert.strictEqual(deal.amount, 150_000);
132→    assert.strictEqual(deal.currency, 'USD');
133→    assert.strictEqual(deal.contactId, contactId);
134→    assert.strictEqual(deal.managerId, managerId);
135→    assert.strictEqual(deal.description, 'Custom description');
136→  });
137→
138→  it('should generate unique numbers for each deal', async () => {
139→    const a = await deals.create({ title: 'Unique A', pipelineId, stageId: newStageId });
140→    const b = await deals.create({ title: 'Unique B', pipelineId, stageId: newStageId });
141→    assert.notStrictEqual(a.number, b.number, 'Each deal must have a unique number');
142→  });
143→
144→  // ── findMany ────────────────────────────────────────────────────────
145→
146→  it('should findMany returning all non-deleted deals', async () => {
147→    const list = await deals.findMany();
148→    assert.ok(Array.isArray(list));
149→    assert.ok(list.length >= 3, 'Should find at least the deals we created');
150→    for (const d of list) {
151→      assert.strictEqual(d.deletedAt, null, 'No soft-deleted deals in results');
152→    }
153→  });
154→
155→  it('should findMany filtered by pipelineId', async () => {
156→    const list = await deals.findMany({ where: { pipelineId } });
157→    assert.ok(list.length >= 3);
158→    for (const d of list) {
159→      assert.strictEqual(d.pipelineId, pipelineId);
160→    }
161→  });
162→
163→  it('should findMany filtered by stageId', async () => {
164→    const list = await deals.findMany({ where: { stageId: newStageId } });
165→    assert.ok(list.length >= 3);
166→    for (const d of list) {
167→      assert.strictEqual(d.stageId, newStageId);
168→    }
169→  });
170→
171→  it('should findMany with status=open (closedAt=null)', async () => {
172→    const list = await deals.findMany({ where: { closedAt: null } });
173→    assert.ok(list.length >= 3);
174→    for (const d of list) {
175→      assert.strictEqual(d.closedAt, null);
176→    }
177→  });
178→
179→  it('should findMany with status=closed (closedAt not null)', async () => {
180→    // Create a deal and manually set closedAt for this filter test
181→    const closedDeal = await deals.create({
182→      title: 'Closed Deal',
183→      pipelineId,
184→      stageId: wonStageId,
185→    });
186→    await prisma.deal.update({
187→      where: { id: closedDeal.id },
188→      data: { closedAt: new Date() },
189→    });
190→
191→    const closedList = await deals.findMany({ where: { closedAt: { not: null } } });
192→    assert.ok(closedList.length >= 1, 'Should find at least one closed deal');
193→    for (const d of closedList) {
194→      assert.ok(d.closedAt !== null, 'All returned deals should have closedAt set');
195→    }
196→
197→    const openList = await deals.findMany({ where: { closedAt: null } });
198→    const closedIds = new Set(closedList.map(d => d.id));
199→    for (const d of openList) {
200→      assert.ok(!closedIds.has(d.id), 'Open deals should not include closed ones');
201→    }
202→  });
203→
204→  it('should exclude soft-deleted deals from findMany', async () => {
205→    await deals.softDelete(createdDealId);
206→    const list = await deals.findMany();
207→    const ids = list.map(d => d.id);
208→    assert.ok(!ids.includes(createdDealId), 'Soft-deleted deal should be excluded from findMany');
209→
210→    // Restore for further tests
211→    await prisma.deal.update({ where: { id: createdDealId }, data: { deletedAt: null } });
212→  });
213→
214→  // ── findUnique ──────────────────────────────────────────────────────
215→
216→  it('should findUnique by ID', async () => {
217→    const deal = await deals.findUnique(createdDealId);
218→    assert.ok(deal, 'Should find existing deal');
219→    assert.strictEqual(deal.id, createdDealId);
220→    assert.strictEqual(deal.number, createdDealNumber);
221→  });
222→
223→  it('should return null for non-existent ID', async () => {
224→    const deal = await deals.findUnique(`${TEST}nonexistent`);
225→    assert.strictEqual(deal, null);
226→  });
227→
228→  it('should return null for soft-deleted deal', async () => {
229→    await deals.softDelete(createdDealId);
230→    const deal = await deals.findUnique(createdDealId);
231→    assert.strictEqual(deal, null, 'Soft-deleted deal should return null');
232→
233→    // Restore
234→    await prisma.deal.update({ where: { id: createdDealId }, data: { deletedAt: null } });
235→  });
236→
237→  it('should findUnique with includes (DealStage, Pipeline, Contact)', async () => {
238→    const deal = await deals.findUnique(createdDealId, {
239→      DealStage: true,
240→      Pipeline: true,
241→      Contact: true,
242→    });
243→    assert.ok(deal, 'Should find the deal');
244→    assert.ok(deal.DealStage, 'DealStage should be included');
245→    assert.strictEqual(deal.DealStage.id, newStageId);
246→    assert.ok(deal.Pipeline, 'Pipeline should be included');
247→    assert.strictEqual(deal.Pipeline.id, pipelineId);
248→  });
249→
250→  it('should findUnique with history include', async () => {
251→    const deal = await deals.findUnique(createdDealId, {
252→      DealHistory: true,
253→    });
254→    assert.ok(deal);
255→    assert.ok(Array.isArray(deal.DealHistory), 'DealHistory should be included as array');
256→  });
257→
258→  // ── update ──────────────────────────────────────────────────────────
259→
260→  it('should update valid fields', async () => {
261→    const updated = await deals.update(createdDealId, {
262→      title: 'Updated Title',
263→      amount: 99_999,
264→    });
265→    assert.strictEqual(updated.title, 'Updated Title');
266→    assert.strictEqual(updated.amount, 99_999);
267→  });
268→
269→  it('should throw when updating non-existent deal', async () => {
270→    await assert.rejects(
271→      () => deals.update(`${TEST}nonexistent`, { title: 'Nope' }),
272→      /Deal with id .+ not found/,
273→      'Should throw descriptive error for non-existent deal',
274→    );
275→  });
276→
277→  it('should throw when updating soft-deleted deal', async () => {
278→    const tmp = await deals.create({ title: 'Update Delete', pipelineId, stageId: newStageId });
279→    await deals.softDelete(tmp.id);
280→
281→    await assert.rejects(
282→      () => deals.update(tmp.id, { title: 'Nope' }),
283→      /Deal with id .+ not found/,
284→    );
285→  });
286→
287→  // ── moveStage ───────────────────────────────────────────────────────
288→
289→  it('should move deal to a new stage and create DealHistory record', async () => {
290→    // Move back to newStage first to have a clean transition
291→    const moved = await deals.moveStage(createdDealId, qualifiedStageId, userId, 'Moving to qualified');
292→    assert.strictEqual(moved.stageId, qualifiedStageId);
293→
294→    const history = await deals.getHistory(createdDealId);
295→    assert.ok(history.length >= 1, 'History should have at least one entry');
296→    const latest = history[0]; // ordered by changedAt desc
297→    assert.strictEqual(latest.toStageId, qualifiedStageId, 'History should record target stage');
298→    assert.strictEqual(latest.comment, 'Moving to qualified');
299→    assert.strictEqual(latest.changedBy, userId);
300→  });
301→
302→  it('should allow same-stage move (records history without rejection)', async () => {
303→    // Note: The implementation does not reject same-stage transitions.
304→    // It records a history entry with fromStageId == toStageId.
305→    // This is a deviation from the task plan which expected "same stage rejects".
306→    await deals.moveStage(createdDealId, qualifiedStageId, userId, 'Same stage re-entry');
307→    const history = await deals.getHistory(createdDealId);
308→    const latest = history[0];
309→    assert.strictEqual(latest.fromStageId, qualifiedStageId);
310→    assert.strictEqual(latest.toStageId, qualifiedStageId);
311→  });
312→
313→  it('should set closedAt and actualCloseDate when moving to won stage', async () => {
314→    const wonDeal = await deals.create({
315→      title: 'Deal To Win',
316→      pipelineId,
317→      stageId: newStageId,
318→    });
319→    await deals.moveStage(wonDeal.id, wonStageId, userId);
320→
321→    const updated = await prisma.deal.findUnique({ where: { id: wonDeal.id } });
322→    assert.ok(updated?.closedAt, 'closedAt should be set when deal is won');
323→    assert.ok(updated?.actualCloseDate, 'actualCloseDate should be set when deal is won');
324→  });
325→
326→  it('should set closedAt and actualCloseDate when moving to lost stage', async () => {
327→    const lostDeal = await deals.create({
328→      title: 'Deal To Lose',
329→      pipelineId,
330→      stageId: newStageId,
331→    });
332→    await deals.moveStage(lostDeal.id, lostStageId, userId);
333→
334→    const updated = await prisma.deal.findUnique({ where: { id: lostDeal.id } });
335→    assert.ok(updated?.closedAt, 'closedAt should be set when deal is lost');
336→    assert.ok(updated?.actualCloseDate, 'actualCloseDate should be set when deal is lost');
337→  });
338→
339→  it('should throw when moving non-existent deal', async () => {
340→    await assert.rejects(
341→      () => deals.moveStage(`${TEST}nonexistent`, qualifiedStageId, userId),
342→      /Deal with id .+ not found/,
343→    );
344→  });
345→
346→  // ── softDelete ──────────────────────────────────────────────────────
347→
348→  it('should soft delete a deal (sets deletedAt, excludes from queries)', async () => {
349→    const target = await deals.create({
350→      title: 'To Delete',
351→      pipelineId,
352→      stageId: newStageId,
353→    });
354→
355→    const deleted = await deals.softDelete(target.id);
356→    assert.ok(deleted.deletedAt, 'deletedAt should be set');
357→
358→    // Excluded from findUnique
359→    const notFound = await deals.findUnique(target.id);
360→    assert.strictEqual(notFound, null, 'Soft-deleted should not be found via findUnique');
361→
362→    // Excluded from findMany
363→    const list = await deals.findMany();
364→    assert.ok(!list.find(d => d.id === target.id), 'Soft-deleted should not appear in findMany');
365→
366→    // Still exists in DB
367→    const raw = await prisma.deal.findUnique({ where: { id: target.id } });
368→    assert.ok(raw, 'Record should still exist in database');
369→    assert.ok(raw.deletedAt, 'Record should have deletedAt set');
370→  });
371→
372→  it('should throw when soft-deleting already deleted deal', async () => {
373→    const target = await deals.create({
374→      title: 'Double Delete',
375→      pipelineId,
376→      stageId: newStageId,
377→    });
